function EventsPage() {
  const events = [
    {
      id: 1,
      title: "Cloud Security Workshop",
      description: "Learn cloud security basics and best practices.",
      date: "2026-04-10",
      location: "Dublin",
      capacity: 50,
    },
    {
      id: 2,
      title: "DevOps Bootcamp",
      description: "Hands-on DevOps tools and CI/CD practice.",
      date: "2026-04-15",
      location: "Online",
      capacity: 100,
    },
    {
      id: 3,
      title: "AWS Fundamentals Seminar",
      description: "Introduction to core AWS services for beginners.",
      date: "2026-04-20",
      location: "Cork",
      capacity: 75,
    },
  ];

  return (
    <div className="page-box">
      <h2>Events</h2>
      <p>Available events are listed below.</p>

      {events.map((event) => (
        <div
          key={event.id}
          style={{
            border: "1px solid #ddd",
            borderRadius: "8px",
            padding: "15px",
            marginBottom: "15px",
            backgroundColor: "#fafafa",
          }}
        >
          <h3>{event.title}</h3>
          <p><strong>Description:</strong> {event.description}</p>
          <p><strong>Date:</strong> {event.date}</p>
          <p><strong>Location:</strong> {event.location}</p>
          <p><strong>Capacity:</strong> {event.capacity}</p>

          <button
            style={{
              padding: "8px 16px",
              backgroundColor: "#1f2937",
              color: "white",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer",
            }}
            onClick={() => alert(`Registered for ${event.title}`)}
          >
            Register
          </button>
        </div>
      ))}
    </div>
  );
}

export default EventsPage;
